#include <vector>
#include <algorithm>
using namespace std;

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    vector<long long> sorted_nums = nums;
    sort(sorted_nums.begin(), sorted_nums.end());
    if (nums == sorted_nums) {
        return 0;
    }

    long long min_and = (1LL << 60) - 1;
    for (int i = 0; i < n; ++i) {
        if (nums[i] != sorted_nums[i]) {
            long long current_and = nums[i] & sorted_nums[i];
            if (current_and < min_and) {
                min_and = current_and;
            }
        }
    }
    return min_and;
}
